package 'For Loop Example' {
	private import SequenceFunctions::*;
    action def straightLineDynamics {
        in power : ISQ::PowerValue;
        in mass : ISQ::MassValue;
        in deltaT : ISQ::TimeValue;
        in initialPosition : ISQ::LengthValue;
        in initialSpeed : ISQ::SpeedValue;
        out finalPosition : ISQ::LengthValue;
        out finalSpeed : ISQ::SpeedValue;
    }
	action def computeMotion {
		in powerProfile :> ISQ::PowerValue[*];
		in vehicleMass :> ISQ::MassValue;
		in initialPosition :> ISQ::LengthValue;
		in initialSpeed :> ISQ::SpeedValue;
		in deltaT :> ISQ::TimeValue;
		out positions :> ISQ::LengthValue[*] := ( );
		private attribute position := initialPosition;
		private attribute speed := initialSpeed;
		for vehiclePower in powerProfile {
			perform action dynamics : straightLineDynamics {
				in power = vehiclePower;
				in mass = vehicleMass;
				in deltaT = deltaT;
				in initialPosition = position;
				in initialSpeed = speed;
				out finalPosition;
				out finalSpeed;
			}
			then assign position := dynamics.finalPosition;
			then assign speed := dynamics.finalSpeed;
			then assign positions := positions->including(position);
		}
	}
}
```

