				in power = vehiclePower;
				in mass = vehicleMass;
				in deltaT = deltaT;
				in initialPosition = position;
				in initialSpeed = speed;
				out finalPosition;
				out finalSpeed;
			}
			then assign position := dynamics.finalPosition;
			then assign speed := dynamics.finalSpeed;
			then assign positions := positions->including(position);
