    action def straightLineDynamics {
        in power : ISQ::PowerValue;
        in mass : ISQ::MassValue;
        in deltaT : ISQ::TimeValue;
        in initialPosition : ISQ::LengthValue;
        in initialSpeed : ISQ::SpeedValue;
        out finalPosition : ISQ::LengthValue;
